update nursing_item_record n
set n.executed_times = n.executed_times + #{times}
where n.nursing_item_name = #{name}
and n.customer_id = #{customerId}
and n.del_flag = '0'

update nursing_item_record n
set n.executed_times = n.executed_times + #{times}
where n.nursing_item_record_id = #{id}
and n.executed_times + #{times} <= n.execution_times * n.purchasing_times
and n.del_flag = '0'
